#include<bits/stdc++.h>
using namespace std;
int fail[1000010],son[1000010][31],cnt[1000010],tot;
void insert(string s)
{
    int p=0,len=s.size();
    for(int i=0;i<len;i++)
    {
        int x=s[i]-'a';
        if(!son[p][x])
        {
            son[p][x]=++tot;
        }
        p=son[p][x];
    }
    cnt[p]=len;
}
void getfail()
{
    queue<int> q;
    for(int i=0;i<26;i++)
    {
        if(son[0][i])
        {
            fail[son[0][i]]=0;
            q.push(son[0][i]);
        }
    }
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i=0;i<26;i++)
        {
            if(son[t][i])
            {
                fail[son[t][i]]=son[fail[t]][i];
                q.push(son[t][i]);
            }
            else
            {
                son[t][i]=son[fail[t]][i];
            }
        }
    }
}
int stk[1000010],top,v[1000010];
void query(string s)
{
    int len=s.size();
    int p=0,ans=0;
    for(int i=0;i<len;i++)
    {
        int x=s[i]-'a';
        p=son[p][x];
        stk[++top]=p;
        v[top]=i;
        if(cnt[p])
        {
            top-=cnt[p];
            if(top)
            {
                p=stk[top];
            }
            else
            {
                p=0;
            }
        }
    }
}
string s[100010];
int main()
{
    int n;
    string str;
    cin>>str;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        cin>>s[i];
        insert(s[i]);
    }
    getfail();
    query(str);
    for(int i=1;i<=top;i++)
    {
        printf("%c",str[v[i]]);
    }
    return 0;
}
